@startuml

class TilePyramid {
}

class TGCEDatatype {
  «enumeration»
  integer
  float
}

class GridCellEncoding {
  «enumeration»
  grid-value-is-center
  grid-value-is-area
  grid-value-is-corner
}

class TiledGriddedCoverage {
  id: Integer
  dataType = tiles
  coverageDataType: TGCEDatatype
  scale: Real
  offset: Real
  precision: Real?
  nullValue: Real?
  gridCellEncoding: GridCellEncoding?
  unitOfMeasure: String?
  fieldName: String?
  quantityDefinition: String?
}

class Tile {
}

class CoverageTile {
  scale: Real
  offset: Real
  min: Real?
  max: Real?
  mean: Real?
  standardDeviation: Real?
}

TiledGriddedCoverage -|> TilePyramid
TiledGriddedCoverage "1" o-- "*" Tile
TiledGriddedCoverage "1" o-- "*" CoverageTile
CoverageTile -|> Tile

@enduml
